object ConfigService {
  def parseConfig(xmlString: String): Map[String, String] = {
    val xml = XML.loadString(xmlString)
    extractSettings(xml)
  }

  private def extractSettings(xml: scala.xml.Elem): Map[String, String] = {
    val settings = new java.util.HashMap[String, String]()
    for (elem <- xml \ "setting") {
